"use client";
import Image from "next/image";
import React from "react";
import { Button } from "../ui/button";
import { PlusSquareIcon, Trash2Icon } from "lucide-react";
import { useCartStore, useCheckoutStore } from "@/store/posStore";
import CheckoutFooter from "./CheckoutFooter";

const ItemCard = ({ barcode }: { barcode: string }) => {
  const products = useCartStore((state) => state.products);
  const increase = useCartStore((state) => state.increaseQuantity);
  const decrease = useCartStore((state) => state.decreaseQuantity);
  // const total = useCartStore((state) => state.grandTotal);
  const filteredProducts = products.filter((products) =>
    barcode.includes(products.productBarcode)
  );
  // const checkedoutProd = useCheckoutStore((state) => state.products);
  // let datas = [];
  // checkedoutProd.length === 0
  //   ? (datas = filteredProducts)
  //   : (datas = checkedoutProd);

  const total = filteredProducts.reduce(
    (acc, product) => acc + product.price * product.quantity,
    0
  );
  return (
    <>
      <main className="max-w-full max-h-full flex relative overflow-y-hidden">
        <div className="xs:mb-25 sm:mb-25 md:mb-25 lg:mb-25 w-screen m-6 grid flex grid-cols-1 items-start justify-center gap-4 sm:grid-cols-1 md:grid-cols-2 lg:grid-cols-3 overflow-y-auto">
          {/* overflow-y-scroll*/}

          {filteredProducts.map((products) => (
            <div
              className="w-full h-50 flex flex-row rounded-lg bg-[#fff]"
              key={products.id}
            >
              <div className="shrink-0">
                <Image
                  key={products.id}
                  src={products.imageUrl}
                  width={150}
                  height={150}
                  alt="image"
                  className="object-contain h-full w-[150]"
                />
              </div>
              <div className="w-full flex flex-col ">
                <div className="py-5 px-0">
                  <h3 className="md:text-lg text-[#5e5e5e] break-all">
                    {products.productName}
                  </h3>
                  <span className="md:text-md font-bold text-[#216c58]">
                    ₱{products.price}
                  </span>
                </div>
                {/* <p className="text-sm pt-5 ml-5 mr-5">{products.description}</p> */}
                <div className="flex m-3 mt-auto">
                  <div className="sm:space-x-3 md:space-x-5 space-x-5 flex flex-row items-center">
                    <Button
                      onClick={() => decrease(products.id)}
                      variant="outline"
                      size="icon"
                      className="size-8 text-[#b94350] border-[#b94350] cursor-pointer hover:bg-[#b94350]"
                    >
                      <Trash2Icon className="" />
                    </Button>
                    <span className="text-sm font-bold text-gray-700 dark:text-white">
                      {products.quantity}
                    </span>
                    <Button
                      onClick={() => increase(products.id)}
                      variant="outline"
                      size="icon"
                      className="size-8 text-[#276857] border-[#276857] cursor-pointer hover:bg-[#78d0b9]"
                    >
                      <PlusSquareIcon className="" />
                    </Button>
                  </div>
                  <div className="flex ml-auto p-3 justify-end items-end break-all">
                    <p className="text-sm text-[#5e5e5e]">
                      Total:&nbsp;
                      <span className="text-sm text-[#216c58] font-bold">
                        ₱{(products.quantity * products.price).toFixed(2)}
                      </span>
                    </p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>
      <div className="">
        <footer className="fixed w-full w-full h-auto bottom-0 bg-[#f8faf7]">
          <CheckoutFooter
            barcodes={filteredProducts}
            grandTotal={total}
            totalItems={filteredProducts.length}
          />
        </footer>
      </div>
    </>
  );
};
export default ItemCard;
